STATIC s_nFrom
STATIC s_nTo
STATIC s_nStep

PROCEDURE Main()

   LOCAL array
   LOCAL tmp, n

   ? "Testing Harbour For Next loops."

   array := { ;
      {  1, 10,  1 }, ;
      { 10,  1, -1 }, ;
      {  1, 10, -1 }, ;
      { 10,  1,  1 }, ;
      {  1, 10,  4 }, ;
      { 10,  1, -4 }, ;
      {  1, 10, -4 }, ;
      { 10,  1,  4 } }

   FOR tmp := 1 TO Len( array )

      s_nFrom := array[ tmp ][ 1 ]
      s_nTo   := array[ tmp ][ 2 ]
      s_nStep := array[ tmp ][ 3 ]

      ? ;
         " From:", s_nFrom, ;
         "   To:", s_nTo, ;
         " Step:", s_nStep

      FOR n := Eval( {|| ValFrom() } ) TO Eval( {|| ValTo() } ) STEP Eval( {|| ValStep() } )
         ? "Exec", n
      NEXT

   NEXT

   RETURN

STATIC FUNCTION ValFrom()

   ? "From"

   RETURN s_nFrom

STATIC FUNCTION ValTo()

   ? "To"

   RETURN s_nTo

STATIC FUNCTION ValStep()

   ? "Step"

   RETURN s_nStep

FUNCTION ft_NetPV( nInitialInvestment, nInterestRate, aCashFlow, nNoOfCashFlows )

   LOCAL nNetPresentValue := 0

   __defaultNIL( @nNoOfCashFlows, Len( aCashFlow ) )

   AEval( aCashFlow, ;
      {| nElement, nElementNo | ;
      nNetPresentValue += nElement / ;
      ( ( 1 + ( nInterestRate / 100 ) ) ^ nElementNo ) }, ;
      1, nNoOfCashFlows )

   RETURN nNetPresentValue -= nInitialInvestment

FUNCTION ft_ElTime( cTIME1, cTIME2 )

   LOCAL  nDELSECS, nHRS, nMINS, nSECS, nSECS1, nSECS2

   nSECS1   := ( Val( SubStr( cTIME1, 1, 2 ) )
      Right( "00" + hb_ntos( nHRS ), 2 ) + ;
      ":" + ;
      Right( "00" + hb_ntos( nMINS ), 2 ) + ;
      ":" + ;
      Right( "00" + hb_ntos( nSECS ), 2 )

