FUNCTION cUserFunction( nMode, nCurElement, nRowPos )

   LOCAL nRetVal := AC_CONT                
   LOCAL nKey    := LastKey()

   LOCAL nRow := Row()
   LOCAL nCol := Col()

   HB_SYMBOL_UNUSED( nRowPos )

   @ 0, 20 SAY Str( nRow, 3 ) + " " + Str( nCol, 3 )

   DO CASE

   CASE nMode == AC_IDLE
      @  0,  0 SAY PadR( hb_ntos( nCurElement ), 10 )
      nRetVal := AC_CONT                   
   CASE nMode == AC_HITTOP                 
      @  0,  0 SAY "Hit Top   "

   CASE nMode == AC_HITBOTTOM              
      @  0,  0 SAY "Hit Bottom"

   CASE nMode == AC_EXCEPT                 
      @  0,  0 SAY "Exception "
      DO CASE
      CASE nKey == K_ENTER                 
         nRetVal := AC_SELECT
      CASE nKey == K_ESC                   
         nRetVal := AC_ABORT
      OTHERWISE
         nRetVal := AC_GOTO                
      ENDCASE
   ENDCASE

   RETURN nRetVal

