FUNCTION ft_Blink( cMsg, nRow, nCol )

   LOCAL cSavColor

   IF cMsg != NIL

      cSavColor := SetColor()


      hb_DispOutAt( ;
         iif( nRow == NIL, Row(), nRow ), ;
         iif( nCol == NIL, Col(), nCol ), ;
         cMsg, ;
         iif( "*" $ Left( cSavColor, 4 ), cSavColor, "*" + cSavColor ) )
   ENDIF

   RETURN NIL

