      hb_StandardLog( hb_BldLogMsg( <data> ), <prio> )
#xcommand LOG <data,...> [PRIO <prio>] => ;
      hb_StandardLog( hb_BldLogMsg( <data> ), <prio> )

#xcommand CLOSE LOG =>  hb_CloseStandardLog()

