               board_[ move2 ][ 4 ] := .T.
               drawbox( board_, move )
               drawbox( board_, possible_[ mpos, 1 ] )
               drawbox( board_, move2 )

            ENDCASE
         ENDCASE
         move := 1
      ENDIF
   ENDDO
