   RestScreen( 0, 0, MaxRow(), MaxCol(), oldscrn )

   RETURN NIL

STATIC FUNCTION DrawBox( board_, nelement )

   SetColor( iif( board_[ nelement ][ 4 ], "+w/rb", "w/n" ) )

   hb_DispBox( ;
      board_[ nelement ][ 1, 1 ], ;
      board_[ nelement ][ 1, 2 ], ;
      board_[ nelement ][ 1, 3 ], ;
      board_[ nelement ][ 1, 4 ], hb_UTF8ToStrBox( "┌─┐│┘─└│ " ) )

   hb_DispOutAt( ;
      board_[ nelement ][ 1, 1 ] + 1, ;
      board_[ nelement ][ 1, 2 ] + 2, hb_ntos( nelement ) )

   RETURN NIL

STATIC FUNCTION err_msg( msg )

   LOCAL buffer := SaveScreen( 23, 33, 23, 47 )

   SetCursor( SC_NONE )
   SetColor( "+w/r" )
   hb_DispOutAt( 23, 33, msg )
   Inkey( 2 )
   SetCursor( SC_NORMAL )
   RestScreen( 23, 33, 23, 47, buffer )

   RETURN NIL

STATIC FUNCTION moremoves( board_ )

   LOCAL xx, yy, canmove := .F., piecesleft := 0, buffer

   FOR xx := 1 TO 33
      FOR yy := 1 TO Len( board_[ xx ][ 2 ] )
         IF board_[ xx ][ 4 ] .AND.  ;                     
            board_[ board_[ xx ][ 2, yy ] ][ 4 ] .AND. ;   
            ! board_[ board_[ xx ][ 3, yy ] ][ 4 ]         
            canmove := .T.
            EXIT
         ENDIF
      NEXT

      IF board_[ xx ][ 4 ]
         piecesleft++
      ENDIF
   NEXT
   IF ! canmove
      SetColor( "+w/b" )
      buffer := SaveScreen( 18, 55, 21, 74 )
      DOUBLEBOX( 18, 55, 21, 74 )
      hb_DispOutAt( 19, 58, "No more moves!" )
      hb_DispOutAt( 20, 58, hb_ntos( piecesleft ) + " pieces left" )
      Inkey( 0 )
      RestScreen( 18, 55, 21, 74, buffer )
   ENDIF

   RETURN canmove

THREAD STATIC t_aRgnStack := {}

FUNCTION ft_SavRgn( nTop, nLeft, nBottom, nRight )

   RETURN hb_BChar( nTop ) + hb_BChar( nLeft ) + hb_BChar( nBottom ) + hb_BChar( nRight ) + ;
      SaveScreen( nTop, nLeft, nBottom, nRight )

FUNCTION ft_RstRgn( cScreen, nTop, nLeft )

   IF PCount() == 3
      RestScreen( nTop, nLeft, ;
         ( nTop  - hb_BCode( hb_BSubStr( cScreen, 1, 1 ) ) ) + hb_BCode( hb_BSubStr( cScreen, 3, 1 ) ), ;
         ( nLeft - hb_BCode( hb_BSubStr( cScreen, 2, 1 ) ) ) + hb_BCode( hb_BSubStr( cScreen, 4, 1 ) ), ;
         hb_BSubStr( cScreen, 5 ) )
   ELSE
      RestScreen( ;
         hb_BCode( hb_BSubStr( cScreen, 1, 1 ) ), ;
         hb_BCode( hb_BSubStr( cScreen, 2, 1 ) ), ;
         hb_BCode( hb_BSubStr( cScreen, 3, 1 ) ), ;
         hb_BCode( hb_BSubStr( cScreen, 4, 1 ) ), ;
         hb_BSubStr( cScreen, 5 ) )
   ENDIF

   RETURN NIL


FUNCTION ft_RgnStack( cAction, nTop, nLeft, nBottom, nRight )

   THREAD STATIC t_nStackPtr := 0

   LOCAL nPopTop

   IF cAction == "push"

      ASize( t_aRgnStack, ++t_nStackPtr )[ t_nStackPtr ] := ;
         ft_SavRgn( nTop, nLeft, nBottom, nRight )

   ELSEIF cAction == "pop" .OR. cAction == "pop all"

      nPopTop := iif( "all" $ cAction, 0, t_nStackPtr - 1 )

      DO WHILE t_nStackPtr > nPopTop
         ft_RstRgn( t_aRgnStack[ t_nStackPtr-- ] )
      ENDDO

      ASize( t_aRgnStack, t_nStackPtr )

   ENDIF

   RETURN NIL

FUNCTION hb_HPDF_IsVersion( ma, mi, mu )

   LOCAL HPDF_MAJOR_VERSION, HPDF_MINOR_VERSION, HPDF_BUGFIX_VERSION

   hb_HPDF_Version( @HPDF_MAJOR_VERSION, @HPDF_MINOR_VERSION, @HPDF_BUGFIX_VERSION )

   RETURN ;
      HPDF_MAJOR_VERSION > ma .OR. ;
      ( HPDF_MAJOR_VERSION == ma .AND. ;
      ( HPDF_MINOR_VERSION > mi .OR. ;
      ( HPDF_MINOR_VERSION == mi .AND. HPDF_BUGFIX_VERSION >= mu ) ) )

